    /**
     * Get all of SBPI_INSTR's bit fields.
     *
     * (read-write) Dispatch instructions to the SBPI interface, used for
     * programming the OTP fuses.
     */
    inline void get_SBPI_INSTR(uint8_t &SHORT_WDATA, uint8_t &CMD,
                               uint8_t &TARGET, uint8_t &PAYLOAD_SIZE_M1,
                               bool &HAS_PAYLOAD, bool &IS_WR) volatile
    {
        uint32_t curr = SBPI_INSTR;

        SHORT_WDATA = curr & 0xffu;
        CMD = (curr >> 8u) & 0xffu;
        TARGET = (curr >> 16u) & 0xffu;
        PAYLOAD_SIZE_M1 = (curr >> 24u) & 0xfu;
        HAS_PAYLOAD = curr & (1u << 28u);
        IS_WR = curr & (1u << 29u);
    }

    /**
     * Set all of SBPI_INSTR's bit fields.
     *
     * (read-write) Dispatch instructions to the SBPI interface, used for
     * programming the OTP fuses.
     */
    inline void set_SBPI_INSTR(uint8_t SHORT_WDATA, uint8_t CMD,
                               uint8_t TARGET, uint8_t PAYLOAD_SIZE_M1,
                               bool HAS_PAYLOAD, bool IS_WR,
                               bool EXEC) volatile
    {
        uint32_t curr = SBPI_INSTR;

        curr &= ~(0xffu);
        curr |= (SHORT_WDATA & 0xffu);
        curr &= ~(0xffu << 8u);
        curr |= (CMD & 0xffu) << 8u;
        curr &= ~(0xffu << 16u);
        curr |= (TARGET & 0xffu) << 16u;
        curr &= ~(0xfu << 24u);
        curr |= (PAYLOAD_SIZE_M1 & 0xfu) << 24u;
        curr &= ~(0b1u << 28u);
        curr |= (HAS_PAYLOAD & 0b1u) << 28u;
        curr &= ~(0b1u << 29u);
        curr |= (IS_WR & 0b1u) << 29u;
        curr &= ~(0b1u << 30u);
        curr |= (EXEC & 0b1u) << 30u;

        SBPI_INSTR = curr;
    }

