    /**
     * Get all of SBPI_STATUS's bit fields.
     */
    inline void get_SBPI_STATUS(bool &RDATA_VLD, bool &INSTR_DONE,
                                bool &INSTR_MISS, bool &FLAG,
                                uint8_t &MISO) volatile
    {
        uint32_t curr = SBPI_STATUS;

        RDATA_VLD = curr & 1u;
        INSTR_DONE = curr & (1u << 4u);
        INSTR_MISS = curr & (1u << 8u);
        FLAG = curr & (1u << 12u);
        MISO = (curr >> 16u) & 0xffu;
    }

    /**
     * Set all of SBPI_STATUS's bit fields.
     */
    inline void set_SBPI_STATUS(bool RDATA_VLD, bool INSTR_DONE,
                                bool INSTR_MISS) volatile
    {
        uint32_t curr = SBPI_STATUS;

        curr &= ~(0b1u);
        curr |= (RDATA_VLD & 0b1u);
        curr &= ~(0b1u << 4u);
        curr |= (INSTR_DONE & 0b1u) << 4u;
        curr &= ~(0b1u << 8u);
        curr |= (INSTR_MISS & 0b1u) << 8u;

        SBPI_STATUS = curr;
    }

